#!/usr/bin/perl
use CGI qw(:standard);
use strict;
use warnings;

my $log_dir = '/path/to/log/files'; # Change this to your log directory
my $q = CGI->new;
print $q->header('text/plain');

my $filename = $q->param('logfile');

if ($filename) {
    my $filepath = "$log_dir/$filename";
    
    if (-e $filepath && -r $filepath) {
        open(my $fh, '<', $filepath) or die "Could not open file '$filepath' $!";
        while (my $line = <$fh>) {
            print $line;
        }
        close($fh);
    } else {
        print "File does not exist or is not readable.";
    }
} else {
    print "No logfile specified.";
}